const main = require('../../lib/jibo-emotion-system');

let SensorySystem = main.sensing.SensorySystem;
let Sensor = main.sensing.sensors.Sensor;
let EmotionSystem = main.emotionSystem.EmotionSystem;
const jibo = require('../../../jibo');

let es, sensor1, sensor0;

describe('SensorySystem', () => {

    let clock;
    beforeEach((done) => {
        clock = sinon.useFakeTimers();
        es = new EmotionSystem();
        es.init({
            jibo: jibo
        });
        sensor1 = new Sensor('TestSensor1', false, es);
        done();
    });

    afterEach(() => {
        clock.restore();
        es.dispose();
    });

    it('Should initialize', () => {
        expect(() => {
            let ss = new SensorySystem(es);
            ss.init([sensor1]);
            ss.dispose();
        }).to.not.throw();
    });

    it('should create a sensor', () => {
        expect(() => {
            sensor0 = new Sensor('test', false, es);
        }).to.not.throw();
    });

    it('should dispose of a sensor', () => {
        expect(() => {
            sensor0.dispose()
        }).to.not.throw();
    });


    it('Should provide sensor by name', () => {
        let ss = new SensorySystem(es);
        ss.init([
            sensor1
        ]);
        expect(ss.getSensor('TestSensor1')).to.equal(sensor1);
        ss.dispose();
    });

    it('Dispose of sensors on dispose', () => {
        let ss = new SensorySystem(es);
        ss.init([
            sensor1
        ]);
        expect(ss.getSensor('TestSensor1')).to.equal(sensor1);
        ss.dispose();
        expect(ss.getSensor('TestSensor1')).to.equal(undefined);
    });

});
